refsection.programlisting:
CREATE TABLE clusterrelate ( id serial, geom geometry);
INSERT INTO clusterrelate (geom) VALUES ('LINESTRING(0 0,1 1)'), ('LINESTRING(2 2,1 1)'), ('LINESTRING(0 1,1 0)'), ('LINESTRING(0 1,0 4)'), ('LINESTRING(2 2,2 4)'), ('LINESTRING(1.5 2.5,2.5 3.5)');
SELECT id, ST_AsText(geom), ST_ClusterRelateWin(geom, '****0****') OVER () AS cluster FROM clusterrelate;
id | st_astext | cluster ----+-----------------------------+--------- 1 | LINESTRING(0 0,1 1) | 0 2 | LINESTRING(2 2,1 1) | 0 3 | LINESTRING(0 1,1 0) | 1 4 | LINESTRING(0 1,0 4) | 1 5 | LINESTRING(2 2,2 4) | 0 6 | LINESTRING(1.5 2.5,2.5 3.5) | 2
